     }
     else if (rst_count == 5) {
         configure_wdt_cascade(0x200, 0x00, 0xffffffff, 0xffffffff);
@@ -157,6 +163,7 @@ void main(void) {
         *wdt_timer2_en = 0;

         SEND_STDOUT_CTRL(TB_CMD_WARM_RESET);
